    if msg_type == "content_block_start" {
        if let Some(cb) = json.get("content_block") {
            if cb.get("type").and_then(|t| t.as_str()) == Some("tool_use") {
                let tool_name = cb
                    .get("name")
                    .and_then(|n| n.as_str())
                    .unwrap_or("unknown")
