        )
        .unwrap();
        std::fs::set_permissions(&script_path, std::fs::Permissions::from_mode(0o755)).unwrap();

        unsafe { std::env::set_var("CLAUDE_CMD", script_path.to_str().unwrap()) };

        let db = FactoryDb::new_in_memory().unwrap();
